sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	// Add your code here

	if(!current.isNewRecord()){
		// pick up changes made to user's roles
		//var roles = (gs.getUser().getUserByID(current.office_member).getRoles() +'').split(',');
		//var roles = gs.getUser().getUserByID(current.office_member).getRoles() +'';
		var grRole = new GlideRecord('sys_user_has_role');
		grRole.addQuery('user', current.office_member);
		grRole.query();
		var rolesFound = 0;
		while (grRole.next()) {
			if(rolesFound >=6){
				break;
			}
			// Global Hierarchy Admin
			if(grRole.role.name == 'x_153465_discovert.tasker_organizational_admin'){
				current.user_is_organization_admin = true;
				rolesFound++;
			}
			// Task Administrator 
			if(grRole.role.name == 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin'){
				current.is_global_tasking_authority = true;
				rolesFound++;
			}
			// Task Executive
			if(grRole.role.name == 'x_153465_discovert.Task_Executive'){
				current.is_task_executive = true;
				rolesFound++;
			}
			// Template Administrator
			if(grRole.role.name == 'x_153465_discovert.tasker_process_template_admin'){
				current.can_manage_process_permissions = true;
				rolesFound++;
			}
			// Global Template Designer
			if(grRole.role.name == 'x_153465_discovert.tasker_process_template_global'){
				current.can_manage_global_processes = true;
				rolesFound++;
			}
			// Personal Template Designer
			if(grRole.role.name == 'x_153465_discovert.tasker_process_template_user'){
				current.has_personal_process_rights = true;
				rolesFound++;
			}
		}
	}

})(current, previous);
